bounce_count.dax:
EVALUATE
ROW(
  "Bounce Count",
  CALCULATE(
    DISTINCTCOUNT(Final Table[Cust ID]),
    Final Table[Bounce status] IN {"Tech", "Non Tech"}
  )
)

bounce_percent.dax:
EVALUATE
ROW(
  "Bounce %",
  DIVIDE(
    CALCULATE(
      DISTINCTCOUNT(Final Table[Cust ID]),
      Final Table[Bounce status] IN {"Tech", "Non Tech"}
    ),
    DISTINCTCOUNT(Final Table[Cust ID])
  ) * 100
)

bounce_by_region.dax:
EVALUATE
SUMMARIZECOLUMNS(
  Final Table[Region],
  "Bounce Count", CALCULATE(
    DISTINCTCOUNT(Final Table[Cust ID]),
    Final Table[Bounce status] IN {"Tech", "Non Tech"}
  ),
  "Bounce %", DIVIDE(
    CALCULATE(DISTINCTCOUNT(Final Table[Cust ID]), Final Table[Bounce status] IN {"Tech", "Non Tech"}),
    DISTINCTCOUNT(Final Table[Cust ID])
  ) * 100
)
